<?= $this->include('template/header') ?><h2><?= $title ?></h2><?php if($artikel): foreach($artikel as $row): ?><article class="entry"><h2><a href="<?= base_url('/artikel/'.$row['slug']) ?>"><?= esc($row['judul']) ?></a></h2><p>Kategori: <?= esc($row['nama_kategori'] ?? '-') ?></p><?php if(!empty($row['gambar'])): ?><img src="<?= base_url('/gambar/'.$row['gambar']) ?>" alt="<?= esc($row['judul']) ?>" style="max-width:220px"><?php endif; ?><p><?= esc(substr(strip_tags($row['isi']),0,200)) ?></p></article><hr><?php endforeach; else: ?><h3>Belum ada data.</h3><?php endif; ?><?= $this->include('template/footer') ?>
